const crypto = require('crypto');

// --- 1. Парсим тело ---
let body;
try {
  const raw = $input.first().json.body;
  body = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error('Invalid JSON body');
}

const initData = body.initData || '';
if (!initData) throw new Error('Missing initData');

// --- 2. HMAC-валидация initData по схеме Telegram WebApp ---
const botToken = $input.first().json.bot_token;
if (!botToken) throw new Error('TELEGRAM_BOT_TOKEN env var not set');

// Парсим initData вручную (URLSearchParams недоступен в JS Task Runner sandbox)
const pairs = initData.split('&').map(p => {
  const i = p.indexOf('=');
  return i === -1 ? [p, ''] : [decodeURIComponent(p.slice(0, i)), decodeURIComponent(p.slice(i + 1))];
});
const paramsMap = new Map(pairs);
const hash = paramsMap.get('hash');
paramsMap.delete('hash');

const dataCheckString = [...paramsMap.entries()]
  .sort(([a], [b]) => a.localeCompare(b))
  .map(([k, v]) => `${k}=${v}`)
  .join('\n');

const secretKey = crypto.createHmac('sha256', 'WebAppData').update(botToken).digest();
const computed = crypto.createHmac('sha256', secretKey).update(dataCheckString).digest('hex');

if (computed !== hash) {
  throw new Error('Invalid initData signature');
}

// --- 3. Авторизация: дата initData не старше суток ---
const authDate = Number(paramsMap.get('auth_date')) || 0;
const nowSec = Math.floor(Date.now() / 1000);
if (nowSec - authDate > 86400) {
  throw new Error('initData too old (>24h)');
}

// --- 4. Извлекаем юзера ---
let user;
try { user = JSON.parse(paramsMap.get('user')); }
catch { throw new Error('Cannot parse user from initData'); }
if (!user || !user.id) throw new Error('No user.id in initData');

const chat_id = String(user.id);

// --- 5. Дата/время Москвы, meal_type по часу ---
const now = new Date();
// смещение Москвы +3ч; Date в n8n уже в TZ контейнера (Europe/Moscow), но подстрахуемся:
const pad = (n) => String(n).padStart(2, '0');
const date = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
const time = `${pad(now.getHours())}:${pad(now.getMinutes())}`;
const h = now.getHours();
let meal_type;
if      (h < 11) meal_type = 'завтрак';
else if (h < 16) meal_type = 'обед';
else if (h < 19) meal_type = 'перекус';
else if (h < 24) meal_type = 'ужин';
else             meal_type = 'перекус';

return [{
  json: {
    chat_id,
    user_name: user.first_name || '',
    date,
    time,
    meal_type,
    payload: body,
  }
}];

// Считает состояние на сегодня для дашборда Mini App.
// Логика переиспользует расчёт из ноды Build Context (Phase 3): expected_today + target kcal.
const v = $('Validate & Parse').first().json;
const chat_id = String(v.chat_id);
const today = v.date; // YYYY-MM-DD, TZ Europe/Moscow (из Validate & Parse)
const pad = (n) => String(n).padStart(2, '0');

const profileRows = $('Read Profile').all().map(i => i.json);
const profileRow = profileRows.find(r => String(r.chat_id) === chat_id) || null;
if (!profileRow) {
  return [{ json: { ok: false, error: 'no_profile', date: today } }];
}
const interval = Number(profileRow.training_days_interval) || 1;

// --- Еда за сегодня ---
const foodRows = $('Read Food Log').all().map(i => i.json);
const todayFood = foodRows.filter(r => String(r.date) === today);
const todaySum = todayFood.reduce((a, r) => ({
  kcal: a.kcal + (Number(r.kcal) || 0), protein: a.protein + (Number(r.protein) || 0),
  fat: a.fat + (Number(r.fat) || 0), carbs: a.carbs + (Number(r.carbs) || 0),
}), { kcal: 0, protein: 0, fat: 0, carbs: 0 });
todaySum.kcal = Math.round(todaySum.kcal);
todaySum.protein = Math.round(todaySum.protein * 10) / 10;
todaySum.fat = Math.round(todaySum.fat * 10) / 10;
todaySum.carbs = Math.round(todaySum.carbs * 10) / 10;

// --- Тренировки ---
const workoutRows = $('Read Workout Log').all().map(i => i.json);
const sortedW = workoutRows.filter(r => r.date).sort((a, b) => String(a.date).localeCompare(String(b.date)));
const lastWorkout = sortedW[sortedW.length - 1] || null;

const blocksStateRows = $('Read Workout Blocks').all().map(i => i.json);
const blocksState = {};
for (const r of blocksStateRows) {
  const n = Number(r.block_num); if (!n) continue;
  blocksState[n] = { label: r.label || `№${n}`, active: String(r.active).toUpperCase() === 'TRUE' };
}
if (!Object.keys(blocksState).length) { for (const n of [1,2,3,4]) blocksState[n] = { label: `№${n}`, active: true }; }
const activeNums = Object.keys(blocksState).map(Number).filter(n => blocksState[n].active).sort((a,b)=>a-b);

function nextActiveAfter(lastN, active) { if (!active.length) return null; const after = active.find(n => n > lastN); return after != null ? after : active[0]; }
function parseWorkoutNumber(plan) {
  if (!plan) return null;
  const m = String(plan).match(/№?\s*([1-4])/); if (m) return Number(m[1]);
  const s = String(plan).toLowerCase();
  if (s.includes('грудь') && s.includes('бицепс')) return 1;
  if (s.includes('плечи') && s.includes('грудь')) return 2;
  if (s.includes('спина') && s.includes('трицепс')) return 3;
  if (s.includes('ноги')) return 4;
  return null;
}

let expected_today;
if (!activeNums.length) {
  expected_today = { type: 'rest', days_until_next: null };
} else if (!lastWorkout) {
  const n = activeNums[0];
  expected_today = { type: 'workout', number: n, label: blocksState[n].label };
} else {
  const lastDate = new Date(String(lastWorkout.date));
  const todayD = new Date(today);
  const daysSince = Math.floor((todayD - lastDate) / (1000*60*60*24));
  if (daysSince < interval) {
    expected_today = { type: 'rest', days_until_next: interval - daysSince };
  } else {
    const lastN = parseWorkoutNumber(lastWorkout.day_plan) || 0;
    const nextN = nextActiveAfter(lastN, activeNums);
    expected_today = { type: 'workout', number: nextN, label: blocksState[nextN].label };
  }
}

// --- Цель по ккал на сегодня (как в Build Context) ---
const bmr = Number(profileRow.bmr) || 1600;
const baseline = Number(profileRow.daily_baseline_kcal) || 280;
const goal = String(profileRow.goal || 'maintain').toLowerCase();
const goalMult = ({ lose: 0.8, maintain: 1.0, gain: 1.15 })[goal] || 1.0;

const walkRows = $('Read Walking Log').all().map(i => i.json).filter(r => String(r.date) === today);
const walkKcalToday = walkRows.reduce((s, r) => s + (Number(r.kcal_burned) || 0), 0);

const todayWorkouts = workoutRows.filter(r => String(r.date) === today);
const workoutKcalActual = todayWorkouts.reduce((s, r) => s + (Number(r.kcal_burned) || 0), 0);

let workoutKcalPlanned = 0;
if (expected_today.type === 'workout') {
  const blockNum = expected_today.number;
  const weight = Number(profileRow.weight_kg) || 76;
  const wkRows = $('Read Workouts Catalog').all().map(i => i.json);
  for (const r of wkRows) {
    if (Number(r.block_num) !== blockNum) continue;
    if (!r.exercise) continue;
    const met = Number(r.met) || 0, dm = Number(r.default_min) || 0;
    if (met && dm) workoutKcalPlanned += met * weight * dm / 60;
  }
}
const workoutKcalToday = todayWorkouts.length > 0 ? workoutKcalActual : Math.round(workoutKcalPlanned);

const tdeeToday = bmr + baseline + walkKcalToday + workoutKcalToday;
const targetKcalToday = Math.round(tdeeToday * goalMult);
const targetFloor = Math.round(bmr * 1.1);
const targetCap = Math.round((bmr + baseline) * goalMult * 1.4);
const target = Math.max(targetFloor, Math.min(targetCap, targetKcalToday));

const targetP = Number(profileRow.target_protein_g) || 0;
const targetF = Number(profileRow.target_fat_g) || 0;
const targetC = Number(profileRow.target_carbs_g) || 0;

return [{ json: {
  ok: true,
  date: today,
  workout_today: expected_today.type === 'workout'
    ? { is_workout: true, label: expected_today.label, block_num: expected_today.number }
    : { is_workout: false, label: null, block_num: null, days_until_next: expected_today.days_until_next ?? null },
  kcal:    { target, eaten: todaySum.kcal, left: Math.round(target - todaySum.kcal) },
  protein: { target: targetP, eaten: todaySum.protein, left: Math.round((targetP - todaySum.protein) * 10) / 10 },
  fat:     { target: targetF, eaten: todaySum.fat },
  carbs:   { target: targetC, eaten: todaySum.carbs },
} }];
